from dataclasses import dataclass
from typing import List

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a politician into a readable sentence."""
    if not triples:
        return ""

    # Get the main subject from the first triple
    main_subject = triples[0].subject

    # Create a mapping of predicates to their values
    predicate_map = {}
    for t in triples:
        if t.predicate not in predicate_map:
            predicate_map[t.predicate] = []
        predicate_map[t.predicate].append(t.object)

    # Build sentence components
    sentence_parts = []

    # Start with main identity
    if 'nationality' in predicate_map:
        sentence_parts.append(f"{main_subject} is a {predicate_map['nationality'][0]}")
    elif 'profession' in predicate_map:
        sentence_parts.append(f"{main_subject} is a {predicate_map['profession'][0]}")
    else:
        sentence_parts.append(main_subject)

    # Add birth information
    birth_phrases = []
    if 'birthDate' in predicate_map:
        birth_phrases.append(f"on {predicate_map['birthDate'][0]}")
    elif 'birthYear' in predicate_map:
        birth_phrases.append(f"in {predicate_map['birthYear'][0]}")
    if 'birthPlace' in predicate_map:
        birth_phrases.append(f"in {predicate_map['birthPlace'][0]}")
    if birth_phrases:
        sentence_parts.append(f"who was born {' '.join(birth_phrases)}")

    # Add career information
    if 'office' in predicate_map:
        sentence_parts.append(f"and served as {predicate_map['office'][0]}")
    if 'party' in predicate_map:
        sentence_parts.append(f"with the {predicate_map['party'][0]} party")
    if 'almaMater' in predicate_map:
        sentence_parts.append(f"and studied at {predicate_map['almaMater'][0]}")
    if 'spouse' in predicate_map:
        sentence_parts.append(f"and was married to {predicate_map['spouse'][0]}")

    # Add location information
    if 'country' in predicate_map:
        sentence_parts.append(f"from {predicate_map['country'][0]}")
    if 'state' in predicate_map:
        sentence_parts.append(f"in {predicate_map['state'][0]}")
    if 'region' in predicate_map:
        sentence_parts.append(f"in the {predicate_map['region'][0]} region")

    # Add military information
    if 'militaryBranch' in predicate_map:
        sentence_parts.append(f"and served in the {predicate_map['militaryBranch'][0]}")
    if 'militaryRank' in predicate_map:
        sentence_parts.append(f"with the rank of {predicate_map['militaryRank'][0]}")
    if 'battle' in predicate_map:
        sentence_parts.append(f"and participated in the {predicate_map['battle'][0]}")

    # Add death information
    death_phrases = []
    if 'deathDate' in predicate_map:
        death_phrases.append(f"on {predicate_map['deathDate'][0]}")
    elif 'deathYear' in predicate_map:
        death_phrases.append(f"in {predicate_map['deathYear'][0]}")
    if 'deathPlace' in predicate_map:
        death_phrases.append(f"in {predicate_map['deathPlace'][0]}")
    if death_phrases:
        sentence_parts.append(f"and died {' '.join(death_phrases)}")

    # Add other information
    if 'predecessor' in predicate_map:
        sentence_parts.append(f"and was preceded by {predicate_map['predecessor'][0]}")
    if 'successor' in predicate_map:
        sentence_parts.append(f"and was succeeded by {predicate_map['successor'][0]}")
    if 'award' in predicate_map:
        sentence_parts.append(f"and received the {predicate_map['award'][0]}")
    if 'religion' in predicate_map:
        sentence_parts.append(f"and was a {predicate_map['religion'][0]}")

    # Combine all parts into one complex sentence
    if len(sentence_parts) == 1:
        return sentence_parts[0] + "."
    else:
        result = sentence_parts[0]
        for i, part in enumerate(sentence_parts[1:], 1):
            if part.startswith("who") or part.startswith("and"):
                result += ", " + part
            else:
                result += " " + part
        return result + "."

